pub fn lookup(arch: &str) -> Option<&'static dyn ArchFactory> {
    REGISTRY.get(arch).copied()
}

pub fn entries() -> impl Iterator<Item = (&'static str, &'static dyn ArchFactory)> {
    REGISTRY.entries().map(|(k, v)| (*k, *v))
}

pub fn len() -> usize {
    REGISTRY.len()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn registry_is_populated() {
        assert!(len() > 0);
        assert!(lookup("LlamaForCausalLM").is_some());
    }

    #[test]
    fn registry_resolves_canonical_archs() {
        for arch in [
            "LlamaForCausalLM",
            "Qwen2ForCausalLM",
            "MixtralForCausalLM",
            "MistralForCausalLM",
            "Gemma3ForCausalLM",
            "DeepseekV3ForCausalLM",
        ] {
            assert!(lookup(arch).is_some(), "missing: {arch}");
        }
    }

    #[test]
    fn registry_resolves_gemma4_unified() {
        // Released Gemma 4 12B EXL3 quant (turboderp/gemma-4-12B-it-exl3)
        // ships `architectures: ["Gemma4UnifiedForConditionalGeneration"]`.
        assert!(
            lookup("Gemma4UnifiedForConditionalGeneration").is_some(),
            "Gemma4UnifiedForConditionalGeneration must be registered"
        );
        assert!(lookup("Gemma4UnifiedTextModel").is_some());
    }
}
